// // This module implements a 2-to-4 decoder with an enable input. When the enable signal is LOW, one of the four outputs corresponding to the input binary value should be activated (set to HIGH). When the enable signal is HIGH, all outputs should be LOW.
module decoder2to4 (  
    input wire [1:0] A,  
    input wire EN,  
    output reg [3:0] Y  
);  
    always @(*) begin  
        if (EN) begin  
            case (A)  
                2'b00: Y = 4'b0001;  
                2'b01: Y = 4'b0010;  
                2'b10: Y = 4'b0100;  
                2'b11: Y = 4'b1000;  
                default: Y = 4'b0000;  
            endcase  
        end else begin  
            Y = 4'b0000;  
        end  
    end  
endmodule
